package com.example.ecommerce.search.config;

import org.apache.http.HttpHost;
import org.elasticsearch.client.RestClient;
import org.elasticsearch.client.RestHighLevelClient;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.net.URI;
import java.net.URISyntaxException;
import java.util.Arrays;
import java.util.Objects;

@Configuration
public class ElasticsearchConfig {

    @Value("${spring.elasticsearch.rest.uris}")
    private String[] elasticsearchUris;

    @Bean(destroyMethod = "close")
    public RestHighLevelClient restHighLevelClient() {
        HttpHost[] httpHosts = Arrays.stream(elasticsearchUris)
                .map(uriString -> {
                    try {
                        URI parsedUri = new URI(uriString);
                        return new HttpHost(parsedUri.getHost(), parsedUri.getPort(), parsedUri.getScheme());
                    } catch (URISyntaxException e) {
                        System.err.println("Invalid Elasticsearch URI: " + uriString + " - " + e.getMessage());
                        return null;
                    }
                })
                .filter(Objects::nonNull)
                .toArray(HttpHost[]::new);

        if (httpHosts.length == 0) {
            throw new IllegalStateException("No valid Elasticsearch URIs configured.");
        }

        return new RestHighLevelClient(
                RestClient.builder(httpHosts)
        );
    }
}
