package com.example.ecommerce.search.service;

import com.example.ecommerce.search.model.Product;
import com.example.ecommerce.search.model.SearchResultDto;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.support.master.AcknowledgedResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.rest.RestStatus;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.BucketOrder;
import org.elasticsearch.search.aggregations.bucket.range.Range;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;

@Service
public class ProductService {

    private static final String PRODUCT_INDEX = "products";
    private final RestHighLevelClient esClient;
    private final ObjectMapper objectMapper;

    @Autowired
    public ProductService(RestHighLevelClient esClient, ObjectMapper objectMapper) {
        this.esClient = esClient;
        this.objectMapper = objectMapper;
    }

    @PostConstruct
    public void init() {
        try {
            createProductIndexWithMapping();
        } catch (IOException e) {
            System.err.println("Failed to create product index with mapping on startup: " + e.getMessage());
        }
    }

    public void createProductIndexWithMapping() throws IOException {
        GetIndexRequest request = new GetIndexRequest(PRODUCT_INDEX);
        boolean exists = esClient.indices().exists(request, RequestOptions.DEFAULT);

        if (!exists) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest(PRODUCT_INDEX);
            createIndexRequest.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0)
            );

            createIndexRequest.mapping(
                    "{\n" +
                            "  \"properties\": {\n" +
                            "    \"id\": { \"type\": \"keyword\" },\n" +
                            "    \"name\": { \"type\": \"text\", \"fields\": { \"keyword\": { \"type\": \"keyword\", \"ignore_above\": 256 } } },\n" +
                            "    \"description\": { \"type\": \"text\" },\n" +
                            "    \"category\": { \"type\": \"keyword\" },\n" +
                            "    \"brand\": { \"type\": \"keyword\" },\n" +
                            "    \"price\": { \"type\": \"double\" },\n" +
                            "    \"imageUrl\": { \"type\": \"keyword\", \"index\": false },\n" +
                            "    \"available\": { \"type\": \"boolean\" }\n" +
                            "  }\n" +
                            "}",
                    XContentType.JSON
            );
            esClient.indices().create(createIndexRequest, RequestOptions.DEFAULT);
            System.out.println("Product index created with mapping.");
        } else {
            System.out.println("Product index already exists.");
        }
    }

    public boolean deleteProductIndex() throws IOException {
        DeleteIndexRequest request = new DeleteIndexRequest(PRODUCT_INDEX);
        AcknowledgedResponse deleteResponse = esClient.indices().delete(request, RequestOptions.DEFAULT);
        return deleteResponse.isAcknowledged();
    }

    public String indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isEmpty()) {
            product.setId(UUID.randomUUID().toString());
        }

        IndexRequest request = new IndexRequest(PRODUCT_INDEX);
        request.id(product.getId());
        request.source(objectMapper.writeValueAsString(product), XContentType.JSON);

        IndexResponse response = esClient.index(request, RequestOptions.DEFAULT);
        if (response.status() == RestStatus.CREATED || response.status() == RestStatus.OK) {
            return response.getId();
        } else {
            throw new IOException("Failed to index product: " + response.status());
        }
    }

    public SearchResultDto searchProducts(String query, List<String> categories, List<String> brands,
                                          Double minPrice, Double maxPrice, int page, int size) throws IOException {

        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (query != null && !query.trim().isEmpty()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description"));
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (categories != null && !categories.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category", categories));
        }
        if (brands != null && !brands.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand", brands));
        }
        if (minPrice != null || maxPrice != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("price")
                    .gte(minPrice != null ? minPrice : 0)
                    .lte(maxPrice != null ? maxPrice : Double.MAX_VALUE));
        }
        
        // Only include available products by default
        boolQuery.filter(QueryBuilders.termQuery("available", true));

        searchSourceBuilder.query(boolQuery);

        // Pagination
        searchSourceBuilder.from(page * size);
        searchSourceBuilder.size(size);

        // Facet Aggregations
        searchSourceBuilder.aggregation(AggregationBuilders
                .terms("categories_agg")
                .field("category")
                .size(10) // Top 10 categories
                .order(BucketOrder.count(false)));

        searchSourceBuilder.aggregation(AggregationBuilders
                .terms("brands_agg")
                .field("brand")
                .size(10) // Top 10 brands
                .order(BucketOrder.count(false)));

        searchSourceBuilder.aggregation(AggregationBuilders
                .range("price_ranges_agg")
                .field("price")
                .addRange(0, 50.0)    // 0-50
                .addRange(50.0, 100.0)   // 50-100
                .addRange(100.0, 200.0)  // 100-200
                .addUnboundedTo(200.0)   // 200+ (values >= 200)
        );

        searchRequest.source(searchSourceBuilder);

        SearchResponse searchResponse = esClient.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            products.add(objectMapper.readValue(hit.getSourceAsString(), Product.class));
        }

        Map<String, Map<String, Long>> facets = new HashMap<>();

        Terms categoriesAgg = searchResponse.getAggregations().get("categories_agg");
        if (categoriesAgg != null) {
            Map<String, Long> categoryFacets = new HashMap<>();
            categoriesAgg.getBuckets().forEach(bucket ->
                    categoryFacets.put(bucket.getKeyAsString(), bucket.getDocCount()));
            facets.put("category", categoryFacets);
        }

        Terms brandsAgg = searchResponse.getAggregations().get("brands_agg");
        if (brandsAgg != null) {
            Map<String, Long> brandFacets = new HashMap<>();
            brandsAgg.getBuckets().forEach(bucket ->
                    brandFacets.put(bucket.getKeyAsString(), bucket.getDocCount()));
            facets.put("brand", brandFacets);
        }

        Range priceRangesAgg = searchResponse.getAggregations().get("price_ranges_agg");
        if (priceRangesAgg != null) {
            Map<String, Long> priceFacets = new HashMap<>();
            priceRangesAgg.getBuckets().forEach(bucket -> {
                String key = bucket.getKeyAsString();
                // Map Elasticsearch generated keys to more human-readable labels
                if (key.equals("0.0-50.0")) key = "0-50";
                else if (key.equals("50.0-100.0")) key = "50-100";
                else if (key.equals("100.0-200.0")) key = "100-200";
                else if (key.equals("200.0-*")) key = "200+";
                
                priceFacets.put(key, bucket.getDocCount());
            });
            facets.put("price", priceFacets);
        }

        return SearchResultDto.builder()
                .products(products)
                .totalHits(searchResponse.getHits().getTotalHits().value)
                .facets(facets)
                .currentPage(page)
                .pageSize(size)
                .build();
    }
}
