package com.example.ecommerce.search.service;

import com.example.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.rest.RestStatus;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.time.Instant;
import java.util.UUID;

@Service
public class SearchQueryService {

    private static final String QUERY_INDEX = "search_queries";
    private final RestHighLevelClient esClient;
    private final ObjectMapper objectMapper;

    @Autowired
    public SearchQueryService(RestHighLevelClient esClient, ObjectMapper objectMapper) {
        this.esClient = esClient;
        this.objectMapper = objectMapper;
    }

    @PostConstruct
    public void init() {
        try {
            createSearchQueryIndexWithMapping();
        } catch (IOException e) {
            System.err.println("Failed to create search query index with mapping on startup: " + e.getMessage());
        }
    }

    public void createSearchQueryIndexWithMapping() throws IOException {
        GetIndexRequest request = new GetIndexRequest(QUERY_INDEX);
        boolean exists = esClient.indices().exists(request, RequestOptions.DEFAULT);

        if (!exists) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest(QUERY_INDEX);
            createIndexRequest.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0)
            );

            createIndexRequest.mapping(
                    "{\n" +
                            "  \"properties\": {\n" +
                            "    \"id\": { \"type\": \"keyword\" },\n" +
                            "    \"queryText\": { \"type\": \"text\" },\n" +
                            "    \"timestamp\": { \"type\": \"date\" },\n" +
                            "    \"userId\": { \"type\": \"keyword\" }\n" +
                            "  }\n" +
                            "}",
                    XContentType.JSON
            );
            esClient.indices().create(createIndexRequest, RequestOptions.DEFAULT);
            System.out.println("Search query index created with mapping.");
        } else {
            System.out.println("Search query index already exists.");
        }
    }

    public String saveSearchQuery(String queryText, String userId) throws IOException {
        SearchQuery searchQuery = SearchQuery.builder()
                .id(UUID.randomUUID().toString()) // Generate an ID
                .queryText(queryText)
                .timestamp(Instant.now())
                .userId(userId)
                .build();

        IndexRequest request = new IndexRequest(QUERY_INDEX);
        request.id(searchQuery.getId());
        request.source(objectMapper.writeValueAsString(searchQuery), XContentType.JSON);

        IndexResponse response = esClient.index(request, RequestOptions.DEFAULT);
        if (response.status() == RestStatus.CREATED || response.status() == RestStatus.OK) {
            return response.getId();
        } else {
            throw new IOException("Failed to save search query: " + response.status());
        }
    }
}
