package com.example.ecommerce.search.controller;

import com.example.ecommerce.search.model.Product;
import com.example.ecommerce.search.model.SearchResultDto;
import com.example.ecommerce.search.service.ProductService;
import com.example.ecommerce.search.service.SearchQueryService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductService productService;
    private final SearchQueryService searchQueryService;

    @Autowired
    public ProductController(ProductService productService, SearchQueryService searchQueryService) {
        this.productService = productService;
        this.searchQueryService = searchQueryService;
    }

    @PostMapping
    public ResponseEntity<String> indexProduct(@RequestBody Product product) {
        try {
            String id = productService.indexProduct(product);
            return new ResponseEntity<>("Product indexed with ID: " + id, HttpStatus.CREATED);
        } catch (IOException e) {
            System.err.println("Error indexing product: " + e.getMessage());
            return new ResponseEntity<>("Failed to index product: " + e.getMessage(), HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }

    @GetMapping("/search")
    public ResponseEntity<SearchResultDto> searchProducts(
            @RequestParam(required = false) String query,
            @RequestParam(required = false) List<String> category,
            @RequestParam(required = false) List<String> brand,
            @RequestParam(required = false) Double minPrice,
            @RequestParam(required = false) Double maxPrice,
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "10") int size,
            @RequestParam(required = false) String userId
    ) {
        try {
            if (query != null && !query.trim().isEmpty()) {
                searchQueryService.saveSearchQuery(query, userId);
            }

            SearchResultDto searchResult = productService.searchProducts(query, category, brand, minPrice, maxPrice, page, size);
            return new ResponseEntity<>(searchResult, HttpStatus.OK);
        } catch (IOException e) {
            System.err.println("Error searching products: " + e.getMessage());
            return new ResponseEntity<>(null, HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }

    @PostMapping("/_recreateIndex")
    public ResponseEntity<String> recreateProductIndex() {
        try {
            if (productService.deleteProductIndex()) {
                productService.createProductIndexWithMapping();
                return new ResponseEntity<>("Product index recreated successfully.", HttpStatus.OK);
            } else {
                return new ResponseEntity<>("Failed to delete product index.", HttpStatus.INTERNAL_SERVER_ERROR);
            }
        } catch (IOException e) {
            System.err.println("Error recreating product index: " + e.getMessage());
            return new ResponseEntity<>("Failed to recreate product index: " + e.getMessage(), HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }
}